%[text] # 例2.5（大津法）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example2_05"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96],'bilinear');

%%
%[text] ## 変換前の画像表示
figure(1) %[output:6aaed0cf]
imshow(X)  %[output:6aaed0cf]
title('原画像')  %[output:6aaed0cf]

imwrite(X,fullfile(resfolder,myfilename+".png"))

%%
%[text] ## 二値化閾値処理（線形量子化）
tau = 127.5; % 閾値
Xq = (X>=tau);
figure(2) %[output:9b55df17]
imshow(Xq)  %[output:9b55df17]
title('二値化画像（線形量子化')  %[output:9b55df17]

imwrite(Xq,fullfile(resfolder,"fig02-07a.png"))

%%
%[text] ## 二値化閾値処理（大津法）
[hx,indx] = histcounts(X(:),0:256); 
n0 = 0;
n1 = numel(X);
c0 = 0;
c1 = sum((0:255).*hx);
maxsigmaB2 = 0;
for t = 1:255
    n0 = n0 + hx(t);
    n1 = n1 - hx(t);
    c0 = c0 + (t-1)*hx(t);
    c1 = c1 - (t-1)*hx(t);
    mu0 = (n0>0) * c0/n0;
    mu1 = (n1>0) * c1/n1;
    sigmaB2 = n0*n1*(mu0-mu1)^2;
    if sigmaB2 > maxsigmaB2
        maxsigmaB2 = sigmaB2;
        tstar = t;
    end
end
disp("tstar = " + tstar)  %[output:8f6d2e44]
% テキスト式(2.23)では閾値と同じ場合、四捨五入に合わせて 1 とします
Xo = (X>=tstar); 
% MATLAB の関数を使用する場合は以下のようになります。
tau = graythresh(X); % 大津法による閾値。ただし、imbinarizeの仕様で閾値を算出
Xx = imbinarize(X,tau); % 閾値と同じ場合、0 とする二値化処理、テキスト式(2.23)とは異なります
norm(Xo(:)-Xx(:)) % 両者は同じ結果になります。 %[output:3e406717]
figure(3) %[output:727a8c82]
imshow(Xo) %[output:727a8c82]
title('二値化画像（大津法）')  %[output:727a8c82]
%%
%[text] ## 結果出力
imwrite(Xo,fullfile(resfolder,"fig02-07b.png"))
%%
%[text] ## 二値化閾値処理（ディザリング）

T = [ 
    0 128 32 160
   192 64 224 96
   48 176 16 144
   240 112 208 80 ];


Xd = blockproc(X,[4 4],@(blk) blk.data >= T);
figure(4) %[output:47b42539]
imshow(Xd) %[output:47b42539]
title('二値化画像（ディザリング）')  %[output:47b42539]
%%
%[text] ## 結果出力
imwrite(Xd,fullfile(resfolder,"dithering.png"))
%%
%[text] ## 二値化閾値処理（誤差拡散）
X = im2double(X);
V = zeros(size(X),'like',X);
Y = zeros(size(X),'like',X);
E = zeros(size(X),'like',X);
H = [0 0 0; 0 0 7; 3 5 1]/16;
for iRow=1:size(X,1)
    for iCol=1:size(X,2)
        V = imfilter(E,H,'conv');
        Y(iRow,iCol) = (X(iRow,iCol) + V(iRow,iCol))>=0.5;
        E(iRow,iCol) = (X(iRow,iCol) + V(iRow,iCol))-Y(iRow,iCol);
    end
end

figure(5) %[output:3a438887]
imshow(Y) %[output:3a438887]
title('二値化画像（誤差拡散）')  %[output:3a438887]
%%
%[text] ## 結果出力
imwrite(Y,fullfile(resfolder,"errordiffusion.png"))
